#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, k;
        scanf("%d %d", &n, &k);
        int a[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &a[i]);
        }
        long long dp[n][2];
        dp[0][0] = a[0];
        dp[0][1] = 0;
        for (int i = 1; i < n; i++) {
            if (a[i] % 2 == 0) {
                dp[i][0] = dp[i-1][1] + a[i];
                dp[i][1] = dp[i-1][0];
            } else {
                dp[i][0] = dp[i-1][1] + a[i];
                dp[i][1] = dp[i-1][0];
            }
            if (i >= k) {
                if (a[i] % 2 == 0) {
                    dp[i][0] = Math.max(dp[i][0], dp[i-k][1] + a[i]);
                } else {
                    dp[i][0] = Math.max(dp[i][0], dp[i-k][1] + a[i]);
                }
            }
        }
        printf("%lld\n", Math.max(dp[n-1][0], dp[n-1][1]));
    }
    return 0;
}

